import type { AnalysisData } from "@/components/analysis-result"

const API_BASE =
  typeof process !== "undefined" && process.env.NEXT_PUBLIC_API_URL
    ? process.env.NEXT_PUBLIC_API_URL
    : "http://localhost:8000"

interface BackendAnalysisResponse {
  claim: string
  verdict: string
  confidence: number
  technique: string
  explanation: string
  literacy_lesson: string
  reasoning: string
  sources: Array<{
    claim: string
    verdict: string
    source: string
    url: string
  }>
}

interface BackendErrorResponse {
  error?: string
  detail?: string | Array<{ msg: string }>
}

function normalizeVerdict(verdict: string): AnalysisData["verdict"] {
  const v = verdict.toLowerCase()
  if (v === "true" || v === "false" || v === "misleading" || v === "unverified")
    return v
  return "unverified"
}

export async function analyzeClaim(claim: string): Promise<AnalysisData> {
  let response: Response
  try {
    response = await fetch(`${API_BASE}/analyse`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ claim }),
    })
  } catch (e) {
    const msg =
      e instanceof TypeError && e.message === "Failed to fetch"
        ? `Could not reach the API at ${API_BASE}. Is the backend running? (e.g. \`cd backend && python3 -m uvicorn main:app --reload --port 8000\`)`
        : e instanceof Error
          ? e.message
          : "Network error"
    throw new Error(msg)
  }

  const body = (await response.json().catch(() => ({}))) as
    | BackendAnalysisResponse
    | BackendErrorResponse

  if (!response.ok) {
    const err =
      "error" in body && typeof body.error === "string"
        ? body.error
        : "detail" in body && typeof body.detail === "string"
          ? body.detail
          : `Request failed (${response.status})`
    throw new Error(err)
  }

  if ("error" in body && body.error) {
    throw new Error(body.error)
  }

  const data = body as BackendAnalysisResponse

  return {
    verdict: normalizeVerdict(data.verdict),
    technique: data.technique ?? "Unknown",
    explanation: data.explanation ?? "",
    literacyLesson: data.literacy_lesson ?? "",
    matchedSources: (data.sources ?? []).map((s) => ({
      title: s.source,
      url: s.url,
      snippet: s.claim || s.source,
      relevanceScore: 1,
    })),
  }
}
